@work-leaf patch add terminal UI and harness coverage for vim-style visual selections before implementing the feature
diff --git a/tests/terminal_ui.rs b/tests/terminal_ui.rs
index 0fd3564..0a0c3a5 100644
--- a/tests/terminal_ui.rs
+++ b/tests/terminal_ui.rs
@@ -62,6 +62,68 @@ fn vim_style_keys_drive_mode_focus_visibility_and_tabs() {
     assert_eq!(ui.active_window(), 0);
 }

+#[test]
+fn visual_character_mode_selects_and_yanks_focused_right_pane_text() {
+    let mut ui = TerminalUi::new(80, 12);
+    let content = "alpha\nbeta\nchat> ";
+
+    ui.handle_key(UiKey::CtrlW);
+    ui.handle_key(UiKey::Char('l'));
+    ui.render_screen(content);
+
+    ui.handle_key(UiKey::Char('v'));
+    assert_eq!(ui.visual_selection_name(), Some("visual"));
+
+    ui.handle_key(UiKey::Char('l'));
+    ui.handle_key(UiKey::Char('l'));
+
+    let selected_frame = ui.render_screen(content);
+    assert!(selected_frame.contains("\u{1b}[7mcha\u{1b}[0mt> "));
+
+    ui.handle_key(UiKey::Char('y'));
+
+    let copied = ui
+        .take_pending_copy_text(content)
+        .expect("visual yank should queue copied text");
+    assert_eq!(copied, "cha");
+    assert_eq!(ui.copied_text(), Some("cha"));
+    assert_eq!(ui.visual_selection_name(), None);
+    assert!(ui.render_screen(content).starts_with("\u{1b}]52;c;Y2hh\u{7}"));
+}
+
+#[test]
+fn visual_line_and_block_modes_select_and_copy_focused_left_pane_text() {
+    let mut ui = TerminalUi::new(100, 20);
+    let chat_a = AgentId::new("chat-a").unwrap();
+    let chat_b = AgentId::new("chat-b").unwrap();
+    ui.add_agent(AgentListEntry::new(chat_a, "parser"));
+    ui.add_agent(AgentListEntry::new(chat_b, "docs"));
+
+    ui.handle_key(UiKey::Char('j'));
+    ui.handle_key(UiKey::Char('V'));
+    assert_eq!(ui.visual_selection_name(), Some("visual-line"));
+
+    ui.handle_key(UiKey::Char('j'));
+    let selected_frame = ui.render_screen("right");
+    assert!(selected_frame.contains("\u{1b}[7m>parser chat-a\u{1b}[0m"));
+    assert!(selected_frame.contains("\u{1b}[7m docs chat-b\u{1b}[0m"));
+
+    ui.handle_key(UiKey::Char('Y'));
+    let copied_lines = ui
+        .take_pending_copy_text("right")
+        .expect("linewise visual yank should queue copied text");
+    assert_eq!(copied_lines, ">parser chat-a\n docs chat-b");
+
+    ui.handle_key(UiKey::Char('\u{16}'));
+    assert_eq!(ui.visual_selection_name(), Some("visual-block"));
+
+    ui.handle_key(UiKey::Char('l'));
+    ui.handle_key(UiKey::Char('l'));
+    ui.handle_key(UiKey::Char('j'));
+    ui.handle_key(UiKey::Char('y'));
+    let copied_block = ui
+        .take_pending_copy_text("right")
+        .expect("block visual yank should queue copied text");
+    assert_eq!(copied_block, ">pa\n do");
+}
+
