+#[test]
+fn scripted_harness_visual_mode_yanks_focused_right_pane_text() {
+    let mut harness = UiHarness::new(80, 24);
+
+    harness.handle_bytes(&[23, b'l']);
+    harness.render_frame();
+
+    harness.handle_bytes(b"vllly");
+
+    assert_eq!(harness.ui().visual_selection_name(), None);
+    assert_eq!(harness.ui().copied_text(), Some("chat"));
+    assert!(harness.render_frame().starts_with("\u{1b}]52;c;Y2hhdA==\u{7}"));
+}
+
+#[test]
+fn scripted_harness_ctrl_v_starts_visual_block_selection_in_left_pane() {
+    let mut harness = UiHarness::new(80, 24);
+
+    harness.handle_byte(22);
+
+    assert_eq!(harness.ui().visual_selection_name(), Some("visual-block"));
+    assert!(!harness.render_frame().contains("command mode: press i"));
+}
