     fn bell_prefix(&self) -> &'static str {
         if self.pending_bell.replace(false) {
             "\u{7}"
+        } else {
+            ""
+        }
+    }
+
+    fn clipboard_prefix(&self) -> String {
+        let Some(text) = self.pending_clipboard_text.borrow_mut().take() else {
+            return String::new();
+        };
+        format!("\u{1b}]52;c;{}\u{7}", base64_encode(text.as_bytes()))
+    }
+
+    fn handle_visual_key(&mut self, key: UiKey) -> Vec<UiAction> {
+        match key {
+            UiKey::Esc => {
+                self.clear_visual_selection();
+            }
+            UiKey::Char('h') | UiKey::Left => self.move_visual_cursor(0, -1),
+            UiKey::Char('j') | UiKey::Down => self.move_visual_cursor(1, 0),
+            UiKey::Char('k') | UiKey::Up => self.move_visual_cursor(-1, 0),
+            UiKey::Char('l') | UiKey::Right => self.move_visual_cursor(0, 1),
+            UiKey::Char('y') | UiKey::Char('Y') => self.yank_visual_selection(),
+            _ => {}
+        }
+        Vec::new()
+    }
+
+    fn start_visual_selection(&mut self, kind: VisualKind) {
+        let position = self.visual_start_position(self.focus);
+        self.visual_selection = Some(VisualSelection {
+            pane: self.focus,
+            kind,
+            anchor: position,
+            cursor: position,
+        });
+    }
+
+    fn clear_visual_selection(&mut self) {
+        self.visual_selection = None;
+    }
+
+    fn visual_start_position(&self, pane: PaneFocus) -> VisualPosition {
+        match pane {
+            PaneFocus::Left => VisualPosition {
+                row: self.control_selected,
+                column: 0,
+            },
+            PaneFocus::Right => {
+                let lines = self.visual_lines_for(PaneFocus::Right);
+                let row = lines
+                    .iter()
+                    .rposition(|line| line.starts_with("chat> "))
+                    .unwrap_or(0);
+                VisualPosition { row, column: 0 }
+            }
+        }
+    }
+
+    fn move_visual_cursor(&mut self, row_delta: isize, column_delta: isize) {
+        let Some(selection) = self.visual_selection.clone() else {
+            return;
+        };
+        let lines = self.visual_lines_for(selection.pane);
+        if lines.is_empty() {
+            return;
+        }
+        let max_row = lines.len().saturating_sub(1);
+        let next_row = selection
+            .cursor
+            .row
+            .saturating_add_signed(row_delta)
+            .min(max_row);
+        let line_width = lines
+            .get(next_row)
+            .map(|line| line.chars().count().saturating_sub(1))
+            .unwrap_or(0);
+        let next_column = selection
+            .cursor
+            .column
+            .saturating_add_signed(column_delta)
+            .min(line_width);
+        if let Some(selection) = self.visual_selection.as_mut() {
+            selection.cursor = VisualPosition {
+                row: next_row,
+                column: next_column,
+            };
+        }
+    }
+
+    fn yank_visual_selection(&mut self) {
+        let Some(text) = self.selected_visual_text() else {
+            self.clear_visual_selection();
+            return;
+        };
+        self.pending_copy_text = Some(text.clone());
+        self.copied_text = Some(text.clone());
+        self.pending_clipboard_text.replace(Some(text));
+        self.pending_bell.set(true);
+        self.clear_visual_selection();
+    }
+
+    fn selected_visual_text(&self) -> Option<String> {
+        let selection = self.visual_selection.as_ref()?;
+        let lines = self.visual_lines_for(selection.pane);
+        let ranges = selected_ranges(&lines, selection);
+        if ranges.is_empty() {
+            return None;
+        }
+        Some(
+            ranges
+                .iter()
+                .map(|range| {
+                    lines
+                        .get(range.row)
+                        .map(|line| char_slice(line, range.start, range.end))
+                        .unwrap_or_default()
+                })
+                .collect::<Vec<_>>()
+                .join("\n"),
+        )
+    }
+
+    fn remember_visual_lines(&self, right_content: &str) {
+        self.last_visual_lines
+            .replace([self.left_visual_lines(), visual_lines(right_content)]);
+    }
+
+    fn visual_lines_for(&self, pane: PaneFocus) -> Vec<String> {
+        let lines = self.last_visual_lines.borrow();
+        match pane {
+            PaneFocus::Left => lines[0].clone(),
+            PaneFocus::Right => lines[1].clone(),
+        }
+    }
+
+    fn left_visual_lines(&self) -> Vec<String> {
